mapper.select:
select cs.id, cs.merchant_id, cs.group_id, cs.create_time, cs.spec_name, cs.state, csg.group_name as groupName, cmi.merchant_name as merchantName from cm_specification cs left join cm_specification_group csg on cs.group_id = csg.id left join cm_merchant_info cmi on cs.merchant_id = cmi.id where cs.deleted = '0' and cmi.deleted = '0'
and cs.merchant_id = #{vo.merchantId}
and cs.group_id = #{vo.groupId}
and cs.state = #{vo.state}
and cs.spec_name like concat('%', #{vo.specName}, '%')
order by cs.create_time desc
